query:
INSERT INTO position_questions (categoryId, questionText)
SELECT id, 'Yaptığı işi en iyi şekilde yapar. İş disiplini ve görev bilinci yüksektir.' FROM position_categories WHERE positionId = 6 AND name = 'Görev Bilinci'
AND NOT EXISTS (SELECT 1 FROM position_questions WHERE questionText = 'Yaptığı işi en iyi şekilde yapar. İş disiplini ve görev bilinci yüksektir.');

INSERT INTO position_questions (categoryId, questionText)
SELECT id, 'Sorumluluğundaki işleri, şirket kural ve prosedürlerine uygun bir biçimde gerçekleştirir.' FROM position_categories WHERE positionId = 6 AND name = 'Görev Bilinci'
AND NOT EXISTS (SELECT 1 FROM position_questions WHERE questionText = 'Sorumluluğundaki işleri, şirket kural ve prosedürlerine uygun bir biçimde gerçekleştirir.');

